#ifdef __cplusplus
extern "C" {
#endif

#include <omp.h>
#include <math.h>
#include <stdio.h>

#define fp float

#define NUMBER_PAR_PER_BOX 100							

#define NUMBER_THREADS 128								

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))	

typedef struct
{
	fp x, y, z;

} THREE_VECTOR;

typedef struct
{
	fp v, x, y, z;

} FOUR_VECTOR;

typedef struct nei_str
{
	int x, y, z;
	int number;
	long offset;

} nei_str;

typedef struct box_str
{
	int x, y, z;
	int number;
	long offset;

	int nn;
	nei_str nei[26];

} box_str;

typedef struct par_str
{
	fp alpha;

} par_str;

typedef struct dim_str
{
	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;

	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;

} dim_str;

void kernel_cpu(	par_str d_par_cpu,
					dim_str d_dim_cpu,
					box_str *d_box_cpu,
					FOUR_VECTOR *d_rv_cpu,
					fp *d_qv_cpu,
					FOUR_VECTOR *d_fv_cpu)
{
	int bx;

	fp a2 = 2 * d_par_cpu.alpha * d_par_cpu.alpha;

#pragma omp parallel for schedule(static) default(none) shared(d_dim_cpu, d_box_cpu, d_rv_cpu, d_qv_cpu, d_fv_cpu, a2)
	for (bx = 0; bx < d_dim_cpu.number_boxes; bx++) {
		int first_i = d_box_cpu[bx].offset;

		FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
		FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
		fp qB_shared[NUMBER_PAR_PER_BOX];

		// Load rA_shared
		for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
			rA_shared[wtx] = d_rv_cpu[first_i + wtx];
		}

		for (int k = 0; k < (1 + d_box_cpu[bx].nn); k++) {
			int pointer;
			if (k == 0) {
				pointer = bx;
			} else {
				pointer = d_box_cpu[bx].nei[k - 1].number;
			}

			int first_j = d_box_cpu[pointer].offset;

			// Load rB_shared and qB_shared
			for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
				rB_shared[wtx] = d_rv_cpu[first_j + wtx];
				qB_shared[wtx] = d_qv_cpu[first_j + wtx];
			}

			// Compute interactions
			for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
				fp v_acc = 0.0f;
				fp x_acc = 0.0f;
				fp y_acc = 0.0f;
				fp z_acc = 0.0f;

				for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
					fp r2 = rA_shared[wtx].v + rB_shared[j].v - DOT(rA_shared[wtx], rB_shared[j]);
					fp u2 = a2 * r2;
					fp vij = expf(-u2);
					fp fs = 2 * vij;
					THREE_VECTOR d;
					d.x = rA_shared[wtx].x - rB_shared[j].x;
					d.y = rA_shared[wtx].y - rB_shared[j].y;
					d.z = rA_shared[wtx].z - rB_shared[j].z;
					fp fxij = fs * d.x;
					fp fyij = fs * d.y;
					fp fzij = fs * d.z;

					v_acc += qB_shared[j] * vij;
					x_acc += qB_shared[j] * fxij;
					y_acc += qB_shared[j] * fyij;
					z_acc += qB_shared[j] * fzij;
				}

#pragma omp atomic
				d_fv_cpu[first_i + wtx].v += v_acc;
#pragma omp atomic
				d_fv_cpu[first_i + wtx].x += x_acc;
#pragma omp atomic
				d_fv_cpu[first_i + wtx].y += y_acc;
#pragma omp atomic
				d_fv_cpu[first_i + wtx].z += z_acc;
			}
		}
	}

	printf("Total: OpenMP kernel execution completed.\n");
}

#ifdef __cplusplus
}
#endif
